"use strict";(self.webpackChunkwiki=self.webpackChunkwiki||[]).push([[4578],{5728:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"linuxpythonmail","metadata":{"permalink":"/wiki/blog/linuxpythonmail","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2023-05-25-linuxPythonMail.md","source":"@site/blog/2023-05-25-linuxPythonMail.md","title":"Linux Python Mail","description":"Version - 1.3","date":"2023-05-25T00:00:00.000Z","formattedDate":"May 25, 2023","tags":[{"label":"linux","permalink":"/wiki/blog/tags/linux"},{"label":"python","permalink":"/wiki/blog/tags/python"},{"label":"mail","permalink":"/wiki/blog/tags/mail"},{"label":"moniter","permalink":"/wiki/blog/tags/moniter"}],"readingTime":0.485,"hasTruncateMarker":true,"authors":[{"name":"Abhilash Reddy","title":"Learning Linux and Automation","url":"https://github.com/abhilashreddysh","email":"abhilashreddysh.99@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/116741403?v=4","key":"abhi"}],"frontMatter":{"slug":"linuxpythonmail","title":"Linux Python Mail","description":"Version - 1.3","sidebar_position":2,"tags":["linux","python","mail","moniter"],"authors":"abhi"},"nextItem":{"title":"peelSoN","permalink":"/wiki/blog/peelson"}},"content":"Python Script to get linux services update through mail. Can be automated and scheduled to run in time intervals using crontab.\\n\\n\x3c!--truncate--\x3e\\n\\n:::info Version - 1.3\\n[Repository Link](https://github.com/abhilashreddysh/AutomationScripts/tree/main/LinuxPythonMail)\\n:::\\n\\n### Setup\\n\\nYou can use the `generateConfig.py` to generate a config file by providing the required inputs for the first time and later update the generated config file accordingly.\\n\\nTo do it manually create the below file in the project root dir\\n\\n```config title=\\"config.py -- (Generated from generateconfig.py)\\"\\ngmailUser = <Sender Email>\\ngmailPassword = <Password>\\nrecipient = <Recipients Mail>\\nservices_to_be_monitered = <List of Services to be monitered>\\n```"},{"id":"peelson","metadata":{"permalink":"/wiki/blog/peelson","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2023-05-24-peelson.md","source":"@site/blog/2023-05-24-peelson.md","title":"peelSoN","description":"Version - 3.0","date":"2023-05-24T00:00:00.000Z","formattedDate":"May 24, 2023","tags":[{"label":"peelson","permalink":"/wiki/blog/tags/peelson"},{"label":"powershell","permalink":"/wiki/blog/tags/powershell"},{"label":"windows","permalink":"/wiki/blog/tags/windows"}],"readingTime":1.325,"hasTruncateMarker":true,"authors":[{"name":"Abhilash Reddy","title":"Learning Linux and Automation","url":"https://github.com/abhilashreddysh","email":"abhilashreddysh.99@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/116741403?v=4","key":"abhi"}],"frontMatter":{"slug":"peelson","title":"peelSoN","description":"Version - 3.0","sidebar_position":1,"tags":["peelson","powershell","windows"],"authors":"abhi"},"prevItem":{"title":"Linux Python Mail","permalink":"/wiki/blog/linuxpythonmail"}},"content":"Powershell script to prevent the system from going to sleep.Use this script to keep your computer awake by programmatically pressing the ScrollLock key every X seconds\\n\\n\x3c!--truncate--\x3e\\n\\n:::info Version - 3.0\\n[Repository Link](https://github.com/abhilashreddysh/peelSoN)\\n:::\\n:::caution This repository is private\\n:::\\n\\n## FAQ\\n\\n### How to setup ?\\n\\n#### _(Using Script)_\\n\\nUse initsetup.ps1 to setup and Change the task _peelSoN_ trigger from (AtLogon) --\x3e (On Workstation Unlock) in task scheduler to start the script as soon as you login.\\n\\nOR\\n\\n#### _(Manual Method)_\\n\\nDownload and save this folder with the name \\"peelSoN\\" in C:\\\\temp and run start.vbs script. You can also automate the task by setting up a task in task scheduler to run on every given interval.\\n\\n### How to stop the running session ?\\n\\nEvery time the task is executed, a bat file is created on the desktop as killpeel.bat\\nDouble click this bat file to kill the session and turn off peelSoN.\\n\\n### Where are my logs saved ?\\n\\nLogs are saved at `C:\\\\temp\\\\peelSoN\\\\logs`\\n\\n### How to change my logout time ?\\n\\nEdit the launch.bat file at `C:\\\\temp\\\\peelSoN\\\\` and update the `Hour` and `Min` flag according to your needs.\\n\\n```bat title=\\"C:\\\\temp\\\\peelSoN\\\\launch.bat\\"\\nPowershell.exe -File \\"C:\\\\temp\\\\peelSoN\\\\peelson.ps1\\" -Hour 18 -Min 00 -sleep 120\\n```\\n\\nThe above example stops the script at 18:00 (06:00 PM). **You can also update the sleep timer**.\\n\\n## Changelog (latest **_3.0_**)\\n\\n### 3.0\\n\\n- Script will run anonymously and generate a bat file on desktop to kill it.\\n- Auto install script and setup a task\\n\\n### 2.4\\n\\n- Script will now end after the logout time\\n\\n## Authors\\n\\n- [@abhilashreddysh](https://www.github.com/abhilashreddysh) ([Linkedin](https://linkedin.com/in/sh-abhilash))"}]}')}}]);